package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Author  string
	Content string
}

var comments = []Comment{
	{Author: "Alice", Content: "This is a *great* article!"},
	{Author: "Bob", Content: "I _really_ enjoyed this."},
	{Author: "Charlie", Content: "Fantastic read. Thank you!"},
}

var tmpl = `<html>
<head><title>User Comments</title></head>
<body>
<h1>User Comments</h1>
<ul>
{{range .}}
<li><strong>{{.Author}}:</strong> <em>{{.Content}}</em></li>
{{end}}
</ul>
</body>
</html>`

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	t := template.Must(template.New("comments").Parse(tmpl))
	t.Execute(w, comments)
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	http.ListenAndServe(":8080", nil)
}